import{_ as a,o as i,c as r,ae as l}from"./chunks/framework.jfJLTIcL.js";const h=JSON.parse('{"title":"术语表","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/glossary.md","filePath":"zh-CN/glossary.md","lastUpdated":1777544089000}'),o={name:"zh-CN/glossary.md"};function d(t,e,n,c,s,p){return i(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="术语表" tabindex="-1">术语表 <a class="header-anchor" href="#术语表" aria-label="Permalink to &quot;术语表&quot;">​</a></h1><h2 id="admin-key" tabindex="-1">Admin Key <a class="header-anchor" href="#admin-key" aria-label="Permalink to &quot;Admin Key&quot;">​</a></h2><p>Admin Key 只用于 <code>/admin/*</code> 管理接口，例如 Provider 配置、Routing、模型管理和 external API key 管理。它属于宿主机管理员、部署脚本或受控运维环境，不应该写入普通客户端、SDK、Web 前端或第三方集成。</p><p>常见来源：</p><ul><li><code>VILAB_ADMIN_KEY</code> 环境变量</li><li>首次启动生成的 <code>initial-admin-key.json</code></li><li>容器内 <code>vilab init</code> 自动读取的初始管理凭据</li></ul><h2 id="external-api-key" tabindex="-1">external API key <a class="header-anchor" href="#external-api-key" aria-label="Permalink to &quot;external API key&quot;">​</a></h2><p>external API key 是普通客户端、SDK 和业务集成调用 Public API 的凭据，用于 <code>/v1/models</code> 和 <code>/v1/audio/transcriptions</code>。它可以按项目、设备或环境单独创建和吊销。</p><p>常见来源：</p><ul><li>首次启动生成的 <code>initial-api-key.json</code></li><li><code>vilab keys initial</code></li><li><code>vilab keys create --name &quot;&lt;client-name&gt;&quot;</code></li><li>桌面设置页的 External API keys</li></ul><h2 id="provider-api-key" tabindex="-1">Provider API Key <a class="header-anchor" href="#provider-api-key" aria-label="Permalink to &quot;Provider API Key&quot;">​</a></h2><p>Provider API Key 是第三方语音或大模型服务的密钥，例如 Groq、OpenAI 或后续其它 Provider 的 key。它只保存在服务端，用来让 VILab Server 代表客户端调用上游 Provider。</p><p>Provider API Key 不等于 VILab external API key，也不应该分发给客户端。</p><h2 id="public-api" tabindex="-1">Public API <a class="header-anchor" href="#public-api" aria-label="Permalink to &quot;Public API&quot;">​</a></h2><p>Public API 是客户端和 SDK 调用的公开能力接口，当前包括：</p><ul><li><code>GET /v1/models</code></li><li><code>POST /v1/audio/transcriptions</code></li></ul><p>Public API 使用 external API key 鉴权，不接受 Admin Key 作为客户端 token。</p><h2 id="admin-api" tabindex="-1">Admin API <a class="header-anchor" href="#admin-api" aria-label="Permalink to &quot;Admin API&quot;">​</a></h2><p>Admin API 是服务端管理接口，路径统一位于 <code>/admin/*</code>。它使用 Admin Key 鉴权，面向管理员、CLI 和部署脚本，不面向普通客户端。</p><h2 id="远程-vilab-server" tabindex="-1">远程 VILab Server <a class="header-anchor" href="#远程-vilab-server" aria-label="Permalink to &quot;远程 VILab Server&quot;">​</a></h2><p>远程 VILab Server 是部署在云服务器、工作站或局域网宿主机上的统一语音服务。普通客户端默认连接远程 Server，并只保存 Server URL、external API key 和公开模型名。</p><h2 id="本机内嵌服务" tabindex="-1">本机内嵌服务 <a class="header-anchor" href="#本机内嵌服务" aria-label="Permalink to &quot;本机内嵌服务&quot;">​</a></h2><p>本机内嵌服务是桌面 App 内部启动的 VILab Server，主要用于单机离线、开发调试或局域网宿主场景。即使连接本机内嵌服务，普通调用方也应该使用 external API key；Admin Key 仍只留在管理侧。</p>',22)])])}const u=a(o,[["render",d]]);export{h as __pageData,u as default};
